var maxBuilding = function(n, restrictions) {
    if (restrictions.length === 0) {
        return n - 1;
    }

    const arr = Array.from({ length: n + 1 }, (_, i) => i - 1);
    let queue = [[1, 0]];

    for (const [id, mh] of restrictions) {
        queue.push([id, mh]);
    }

    while (queue.length > 0) {
        let next = [];

        for (const [id, mh] of queue) {
            if (arr[id] <= mh) continue;

            arr[id] = mh;

            if (id > 1) next.push([id - 1, arr[id] + 1]);
            if (id < n) next.push([id + 1, arr[id] + 1]);
        }

        queue = next;
    }

    return Math.max(...arr);
};
